return [
  {
    json: {
      item_id: '6d6e2f96ab2c4f86c6bfe17f0f3d5c21d7839ed4f3d8fbf35bc7f7f5ec34f7a1',
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      title: 'Example normalized item before Qdrant gating',
      content_text: 'This example item already passed 00_common_normalize_text_object and is about to enter the cheap deterministic prefilter before vector search.',
      upstream_summary: '',
      dedupe_action: 'full_push',
      status: 'raw'
    }
  }
];

const requiredFields = ['item_id', 'source_type', 'source_name', 'title', 'content_text'];
const missingFields = requiredFields.filter((field) => !String($json[field] || '').trim());
if (missingFields.length) {
  throw new Error(`NormalizedTextObject missing required fields: ${missingFields.join(', ')}`);
}

const normalizeMultiline = (value = '') => String(value)
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const buildLabeledBlock = (label, value = '', multiline = false) => {
  const normalized = multiline ? normalizeMultiline(value) : normalizeSingleLine(value);
  return normalized ? `${label}:\n${normalized}` : '';
};

const uniqueSegments = (segments) => {
  const seen = new Set();
  const result = [];
  for (const segment of segments) {
    const normalized = normalizeMultiline(segment);
    if (!normalized || seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(normalized);
  }
  return result;
};

const buildContentSegments = (text, budget) => {
  const normalized = normalizeMultiline(text);
  if (!normalized || budget <= 0) {
    return [];
  }
  if (normalized.length <= budget) {
    return [normalized];
  }

  const segmentBudget = Math.max(120, Math.floor(budget / 3));
  const middleStart = Math.max(0, Math.floor((normalized.length - segmentBudget) / 2));
  const tailStart = Math.max(0, normalized.length - segmentBudget);

  return uniqueSegments([
    normalized.slice(0, segmentBudget),
    normalized.slice(middleStart, middleStart + segmentBudget),
    normalized.slice(tailStart, tailStart + segmentBudget)
  ]);
};

const contentText = normalizeMultiline($json.content_text || '');
const upstreamSummary = normalizeMultiline($json.upstream_summary || '');
const title = normalizeSingleLine($json.title || '');
const sourceName = normalizeSingleLine($json.source_name || '');
const sourceType = normalizeSingleLine($json.source_type || '');
const sourceHost = normalizeSingleLine($json.source_host || '');
const author = normalizeSingleLine($json.author || '');
const publishedAt = normalizeSingleLine($json.published_at || '');
const mediaType = normalizeSingleLine($json.media_type || '');
const canonicalUrl = normalizeSingleLine($json.canonical_url || '');
const eventFingerprintMaxChars = Math.max(200, Number($env.EMBEDDING_INPUT_MAX_CHARS || 8000));
const eventFingerprintMinChars = Math.max(40, Number($env.QDRANT_SEARCH_MIN_CHARS || 80));

const metadataBlocks = [
  buildLabeledBlock('Title', title),
  buildLabeledBlock('Source Name', sourceName),
  buildLabeledBlock('Source Type', sourceType),
  buildLabeledBlock('Source Host', sourceHost),
  buildLabeledBlock('Author', author),
  buildLabeledBlock('Published At', publishedAt),
  buildLabeledBlock('Media Type', mediaType),
  buildLabeledBlock('Canonical URL', canonicalUrl),
  buildLabeledBlock('Upstream Summary', upstreamSummary.slice(0, Math.min(1200, eventFingerprintMaxChars)), true)
].filter(Boolean);

let eventFingerprintText = metadataBlocks.join('\n\n');
const remainingBudget = Math.max(0, eventFingerprintMaxChars - eventFingerprintText.length - (eventFingerprintText ? 2 : 0));
const contentLabels = ['Content Head', 'Content Middle', 'Content Tail'];
const contentBlocks = buildContentSegments(contentText, remainingBudget)
  .map((segment, index) => buildLabeledBlock(contentLabels[Math.min(index, contentLabels.length - 1)] || `Content Segment ${index + 1}`, segment, true))
  .filter(Boolean);

eventFingerprintText = [...metadataBlocks, ...contentBlocks]
  .filter(Boolean)
  .join('\n\n')
  .slice(0, eventFingerprintMaxChars);

const shouldContinueToQdrant = eventFingerprintText.length >= eventFingerprintMinChars;
const prefilterReason = shouldContinueToQdrant
  ? ''
  : `event_fingerprint_text shorter than ${eventFingerprintMinChars} chars after deterministic prefilter`;

return {
  json: {
    ...$json,
    content_text: contentText,
    event_fingerprint_text: eventFingerprintText,
    event_fingerprint_chars: eventFingerprintText.length,
    prefilter_action: shouldContinueToQdrant ? 'pass' : 'skip',
    prefilter_reason: prefilterReason,
    should_continue_to_qdrant: shouldContinueToQdrant,
    dedupe_action: shouldContinueToQdrant ? String($json.dedupe_action || 'full_push').trim() || 'full_push' : 'silent',
    notification_mode: shouldContinueToQdrant ? String($json.notification_mode || '').trim() : 'silent',
    should_write_to_vault: shouldContinueToQdrant ? $json.should_write_to_vault : false,
    should_notify: shouldContinueToQdrant ? $json.should_notify : false,
    should_upsert_qdrant: shouldContinueToQdrant ? $json.should_upsert_qdrant : false,
    should_continue_to_llm: shouldContinueToQdrant ? true : false,
    status: shouldContinueToQdrant ? String($json.status || 'raw').trim() || 'raw' : 'deduped',
    qdrant_operation: shouldContinueToQdrant ? String($json.qdrant_operation || 'skipped').trim() || 'skipped' : 'skipped',
    qdrant_upsert_response: null
  }
};
